import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const DashboardPage = ({ user }) => {
  const [scores, setScores] = useState([]);
  const [value, setValue] = useState('');
  const [date, setDate] = useState('');
  const [message, setMessage] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    if (!user) { navigate('/login'); return; }
    fetchScores();
  }, [user]);

  const fetchScores = async () => {
    try {
      const { data } = await axios.get('/scores');
      setScores(data);
    } catch (err) {
      setMessage('Unable to fetch scores');
    }
  };

  const addScore = async (e) => {
    e.preventDefault();
    try {
      const { data } = await axios.post('/scores', { value: Number(value), date });
      setScores(data);
      setValue('');
      setDate('');
      setMessage('Score saved');
    } catch (err) {
      setMessage(err.response?.data?.message || 'Error adding score');
    }
  };

  if (!user) return null;

  return (
    <div>
      <h2>User Dashboard</h2>
      <div>
        <p>Name: {user.name}</p>
        <p>Email: {user.email}</p>
        <p>Role: {user.role}</p>
      </div>
      <section>
        <h3>Score Entry (Stableford 1-45)</h3>
        <form onSubmit={addScore}>
          <input type='number' value={value} onChange={(e) => setValue(e.target.value)} min='1' max='45' required />
          <input type='date' value={date} onChange={(e) => setDate(e.target.value)} required />
          <button type='submit'>Add Score</button>
        </form>
        {message && <p>{message}</p>}
        <ul>
          {scores.map((s) => <li key={s._id}>{new Date(s.date).toLocaleDateString()} - {s.value}</li>)}
        </ul>
      </section>
    </div>
  );
};

export default DashboardPage;
